// Checks whether Margot's attendee 'Prospect Lists' are reachable via the Outreach API as prospect
// TAGS (the only list-like signal the v2 API exposes). If attendee/non-attendee tags show up here we
// can automate in-person attendance; if not, we fall back to a CSV export of the lists.
const r = $input.first().json;
const status = r.statusCode;
const body = r.body || r;
if (status && status >= 400) {
  return [{ json: { ok:false, note: status===403 ? 'prospects.read scope missing (403)' : `HTTP ${status}`, status, error:(body&&body.errors)||body } }];
}
const data = (body && body.data) || [];
const tagSet = new Set();
let withTags = 0;
for (const p of data) { const t = (p.attributes && p.attributes.tags) || []; if (t.length) withTags++; for (const x of t) tagSet.add(x); }
const tags = [...tagSet];
const attendanceTags = tags.filter((t) => /attendee|non.?attendee/i.test(t));
return [{ json: {
  ok: true,
  prospects_sampled: data.length,
  prospects_with_tags: withTags,
  distinct_tags: tags.length,
  attendance_lists_as_tags: attendanceTags.length ? attendanceTags : 'NONE FOUND — lists are not tags → use CSV export',
  sample_tags: tags.slice(0, 40),
} }];
